import{_ as o,o as t,c as a,a3 as r}from"./chunks/framework.oxq6d-og.js";const u=JSON.parse('{"title":"Hook lifecycle","description":"","frontmatter":{},"headers":[],"relativePath":"en/hooking/lifecycle.md","filePath":"en/hooking/lifecycle.md"}'),c={name:"en/hooking/lifecycle.md"};function n(s,e,i,d,l,p){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="hook-lifecycle" tabindex="-1">Hook lifecycle <a class="header-anchor" href="#hook-lifecycle" aria-label="Permalink to &quot;Hook lifecycle&quot;">​</a></h1><p><code>create</code>, <code>enable</code>, <code>disable</code>, and <code>destroy</code> are separate operations. NHook and MinHook share these names but do not share the same hit and cleanup behavior.</p><p><code>NHook.create()</code> decodes complete instructions covering at least two bytes and saves original bytes. <code>MinHook.create()</code> builds a trampoline without patching the target. Enable temporarily changes memory protection and restores it afterward. For a remote NHook target, accessible threads are suspended during patching except the NThread driving thread, whose separate suspend accounting must not be disturbed.</p><p>An NHook <code>poll()</code> hit is not itself cleanup. <code>resume(hit)</code> either forces a return value or simulates supported displaced instructions and applies the next context. In the current flow, full accessor <code>deinit()</code> participates in releasing the parked thread and closing resources. Design ownership and cleanup explicitly, and use <code>try/finally</code>.</p><p><code>disable()</code> restores original target bytes. <code>destroy()</code> disables an enabled hook, removes it, and frees MinHook trampoline/relay resources. Test the shutdown path on a controlled target.</p>',5)])])}const f=o(c,[["render",n]]);export{u as __pageData,f as default};
